def build_fixture() -> list:
    fixture = []

    # ── Categories ──────────────────────────────────────────────────────────
    for pk, name, keyword, _base, _step in CATEGORIES:
        fixture.append({
            "model": "store.category",
            "pk": pk,
            "fields": {
                "name": name,
                "image": f"https://picsum.photos/seed/{keyword}/800/600",
            },
        })

    # ── Products ─────────────────────────────────────────────────────────────
    product_pk = 1001
    for cat_pk, cat_name, keyword, base_price, step in CATEGORIES:
        templates = PRODUCT_TEMPLATES[cat_pk]
        assert len(templates) == 50, (
            f"Category '{cat_name}' has {len(templates)} templates, expected 50."
        )
        for i, (name_suffix, description) in enumerate(templates):
            price = round(base_price + i * step, 2)
            image_seed = product_pk  # unique seed per product for Picsum
            fixture.append({
                "model": "store.product",
                "pk": product_pk,
                "fields": {
                    "name": f"{cat_name} – {name_suffix}",
                    "description": description,
                    "price": f"{price:.2f}",
                    "image": f"https://picsum.photos/seed/{image_seed}/600/400",
                    "category": cat_pk,
                },
            })
            product_pk += 1

    return fixture


def main():
    data = build_fixture()

    # Sanity checks
    categories = [e for e in data if e["model"] == "store.category"]
    products   = [e for e in data if e["model"] == "store.product"]
    assert len(categories) == 17,  f"Expected 17 categories, got {len(categories)}"
    assert len(products)   == 850, f"Expected 850 products, got {len(products)}"
    pks = [p["pk"] for p in products]
    assert pks[0]  == 1001
    assert pks[-1] == 1850
    names = [p["fields"]["name"] for p in products]
    assert len(names) == len(set(names)), "Duplicate product names detected!"

    output_path = "store_data.json"
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    print(f"✅ Fixture written to '{output_path}'")
    print(f"   Categories : {len(categories)}")
    print(f"   Products   : {len(products)}  (PKs {pks[0]}–{pks[-1]})")
    print(f"\nLoad with:  python manage.py loaddata {output_path}")


if __name__ == "__main__":
    main()